import { generateText } from 'ai';
import { z } from 'zod';

const detectMissingAuth = async (code: string) => {
  const toolRegex = /tool\s*:\s*\{(.*?\n)*?function\s*:\s*\(([^)]*)\)/gs;
  const matches = code.match(toolRegex);
  if (!matches) return [];

  return matches.map(match => {
    const params = match.match(/\(([^)]*)\)/)?.[1] || '';
    const hasAuth = params.includes('user') || params.includes('session') || params.includes('auth');
    return {
      line: code.indexOf(match),
      hasAuthContext: hasAuth,
      severity: !hasAuth ? 'HIGH' : 'LOW'
    };
  }).filter(issue => !issue.hasAuthContext);
};

// Usage
