const detectApiKeyExposure = (code: string) => {
  const apiKeyPatterns = [
    /apiKey\s*:\s*['"][^'"]+['"]/,
    /authorization\s*:\s*['"][^'"]+['"]/,
    /bearer\s+[^\s]+/i,
    /sk-\w{48}/
  ];

  return apiKeyPatterns
    .map(pattern => ({
      pattern: pattern.source,
      matches: [...code.matchAll(pattern)]
    }))
    .flatMap(result => result.matches.map(m => ({
      start: m.index!,
      end: m.index! + m[0].length,
      exposure: m[0],
      type: result.pattern.includes('sk-') ? 'OPENAI' : 'GENERIC'
    })));
};
