import type { RouteHandler } from 'next/server';

const detectSessionPropagation = (handler: RouteHandler | any) => {
  const code = handler.toString();
  const missingPatterns = [
    { pattern: /generateText|streamText/, requires: 'getServerSession|auth\(\)' },
    { pattern: /useChat|useCompletion/, requires: 'useSession|auth' }
  ];

  return missingPatterns
    .filter(({ pattern, requires }) => 
      code.match(new RegExp(pattern)) && !code.match(new RegExp(requires))
    )
    .map(issue => ({
      missingAuth: issue.requires,
      location: code.slice(0, 200) + '...',
      recommendation: `Add ${issue.requires} before ${issue.pattern}`
    }));
};
